26: // New creates Client from config.
27: // Caller is responsible to call Close() to clean up client.
28: func New(cfg clientv3.Config) (*Client, error) {
29: 	c, err := clientv3.New(cfg)
30: 	if err != nil {
31: 		return nil, err
32: 	}
33: 	kc := &Client{
34: 		Client: c,
35: 	}
36: 	kc.Kubernetes = kc
37: 	return kc, nil
38: }
