83: func (k Client) OptimisticPut(ctx context.Context, key string, value []byte, expectedRevision int64, opts PutOptions) (resp PutResponse, err error) {
84: 	txn := k.KV.Txn(ctx).If(
85: 		clientv3.Compare(clientv3.ModRevision(key), "=", expectedRevision),
86: 	).Then(
87: 		clientv3.OpPut(key, string(value), clientv3.WithLease(opts.LeaseID)),
88: 	)
89: 
90: 	if opts.GetOnFailure {
91: 		txn = txn.Else(clientv3.OpGet(key))
92: 	}
93: 
94: 	txnResp, err := txn.Commit()
95: 	if err != nil {
96: 		return resp, err
97: 	}
98: 	resp.Succeeded = txnResp.Succeeded
99: 	resp.Revision = txnResp.Header.Revision
100: 	if opts.GetOnFailure && !txnResp.Succeeded {
101: 		if len(txnResp.Responses) == 0 {
102: 			return resp, fmt.Errorf("invalid OptimisticPut response: %v", txnResp.Responses)
103: 		}
104: 		resp.KV = kvFromTxnResponse(txnResp.Responses[0])
105: 	}
106: 	return resp, nil
107: }
108: 
109: func (k Client) OptimisticDelete(ctx context.Context, key string, expectedRevision int64, opts DeleteOptions) (resp DeleteResponse, err error) {
110: 	txn := k.KV.Txn(ctx).If(
111: 		clientv3.Compare(clientv3.ModRevision(key), "=", expectedRevision),
112: 	).Then(
113: 		clientv3.OpDelete(key),
114: 	)
115: 	if opts.GetOnFailure {
116: 		txn = txn.Else(clientv3.OpGet(key))
117: 	}
118: 	txnResp, err := txn.Commit()
119: 	if err != nil {
120: 		return resp, err
121: 	}
122: 	resp.Succeeded = txnResp.Succeeded
123: 	resp.Revision = txnResp.Header.Revision
124: 	if opts.GetOnFailure && !txnResp.Succeeded {
125: 		resp.KV = kvFromTxnResponse(txnResp.Responses[0])
126: 	}
127: 	return resp, nil
128: }
