130: func kvFromTxnResponse(resp *pb.ResponseOp) *mvccpb.KeyValue {
131: 	getResponse := resp.GetResponseRange()
132: 	if len(getResponse.Kvs) == 1 {
133: 		return getResponse.Kvs[0]
134: 	}
135: 	return nil
136: }
